import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AddEmployee.css";

const AddEmployee = () => {
  const navigate = useNavigate();
  const { id } = useParams(); // used for edit mode

  const [employee, setEmployee] = useState({
    name: "",
    email: "",
    empId: "",
    dob: "",
    gender: "",
    maritalStatus: "",
    designation: "",
    department: "",
    salary: "",
    role: "",
  });

  /* Load employee for EDIT */
  useEffect(() => {
    if (id) {
      const storedEmployees =
        JSON.parse(localStorage.getItem("employees")) || [];

      const existingEmployee = storedEmployees.find(
        (emp) => emp.id === Number(id)
      );

      if (existingEmployee) {
        setEmployee(existingEmployee);
      }
    }
  }, [id]);

  /* Handle input change */
  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value,
    });
  };

  /* Handle submit (ADD / EDIT) */
  const handleSubmit = (e) => {
    e.preventDefault();

    const existingEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];

    if (id) {
      // EDIT MODE
      const updatedEmployees = existingEmployees.map((emp) =>
        emp.id === Number(id) ? employee : emp
      );

      localStorage.setItem(
        "employees",
        JSON.stringify(updatedEmployees)
      );
    } else {
      // ADD MODE
      const newEmployee = {
        ...employee,
        id: Date.now(),
      };

      localStorage.setItem(
        "employees",
        JSON.stringify([...existingEmployees, newEmployee])
      );
    }

    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">
      <h2>{id ? "Edit Employee" : "Add New Employee"}</h2>

      <form className="add-employee-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label>Name</label>
            <input
              name="name"
              value={employee.name}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Email</label>
            <input
              name="email"
              type="email"
              value={employee.email}
              onChange={handleChange}
              required
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Employee ID</label>
            <input
              name="empId"
              value={employee.empId}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Date of Birth</label>
            <input
              name="dob"
              type="date"
              value={employee.dob}
              onChange={handleChange}
              required
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Gender</label>
            <select
              name="gender"
              value={employee.gender}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>Male</option>
              <option>Female</option>
            </select>
          </div>

          <div className="form-group">
            <label>Marital Status</label>
            <select
              name="maritalStatus"
              value={employee.maritalStatus}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>Single</option>
              <option>Married</option>
            </select>
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Department</label>
            <select
              name="department"
              value={employee.department}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>IT</option>
              <option>Database</option>
              <option>Logistic</option>
            </select>
          </div>

          <div className="form-group">
            <label>Salary</label>
            <input
              name="salary"
              type="number"
              value={employee.salary}
              onChange={handleChange}
              required
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Role</label>
            <select
              name="role"
              value={employee.role}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>Admin</option>
              <option>Employee</option>
            </select>
          </div>
        </div>

        <button type="submit" className="submit-btn">
          {id ? "Update Employee" : "Add Employee"}
        </button>
      </form>
    </div>
  );
};

export default AddEmployee;
